1	type Cell = [number, number];
2	
3	const isNeighbor = (cell: Cell, other: Cell): boolean => {
4	  const [x, y] = cell;
5	  const [ox, oy] = other;
6	  const isSameCell = ox === x && oy === y;
7	  return !isSameCell && Math.abs(ox - x) <= 1 && Math.abs(oy - y) <= 1;
8	};
9	
10	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
11	  liveCells.filter((other) => isNeighbor(cell, other)).length;
12	
13	export function nextGeneration(cells: Cell[]): Cell[] {
14	  return cells.filter((cell) => {
15	    const neighborCount = countLiveNeighbors(cell, cells);
16	    return neighborCount === 2 || neighborCount === 3;
17	  });
18	}
